    const source = readFileSync(PAGE_PATH, "utf-8")
    expect(source).not.toContain("Account Deploy Flow")
  })

  it("does not import AccountDeployFlow directly in page.tsx", () => {
    const source = readFileSync(PAGE_PATH, "utf-8")
    expect(source).not.toContain("AccountDeployFlow")
  })
})

